using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

namespace McpRestServer;

/// <summary>
/// MCP tools that wrap a weather REST API.
/// The MCP SDK discovers tools by scanning for [McpServerToolType] classes
/// and [McpServerTool] methods. Constructor parameters are resolved via DI.
/// </summary>
[McpServerToolType]
public class WeatherTools
{
    private readonly HttpClient _httpClient;

    // The MCP SDK resolves constructor parameters from the DI container.
    // Because we register a named HttpClient ("WeatherApi"), we inject
    // IHttpClientFactory and create the client by name.
    public WeatherTools(IHttpClientFactory httpClientFactory)
    {
        _httpClient = httpClientFactory.CreateClient("WeatherApi");
    }

    [McpServerTool, Description("Get the current weather forecast for a US city by latitude and longitude.")]
    public async Task<string> GetForecast(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        // National Weather Service API: resolve grid point, then fetch forecast
        var pointUrl = $"points/{latitude},{longitude}";
        var pointResponse = await _httpClient.GetAsync(pointUrl);
        pointResponse.EnsureSuccessStatusCode();

        using var pointDoc = await JsonDocument.ParseAsync(
            await pointResponse.Content.ReadAsStreamAsync());
        var forecastUrl = pointDoc.RootElement
            .GetProperty("properties")
            .GetProperty("forecast")
            .GetString()!;

        var forecastResponse = await _httpClient.GetAsync(forecastUrl);
        forecastResponse.EnsureSuccessStatusCode();

        using var forecastDoc = await JsonDocument.ParseAsync(
            await forecastResponse.Content.ReadAsStreamAsync());
        var periods = forecastDoc.RootElement
            .GetProperty("properties")
            .GetProperty("periods");

        // Return the first two forecast periods
        var results = new List<string>();
        foreach (var period in periods.EnumerateArray().Take(2))
        {
            var name = period.GetProperty("name").GetString();
            var detail = period.GetProperty("detailedForecast").GetString();
            results.Add($"{name}: {detail}");
        }

        return string.Join("\n\n", results);
    }

    [McpServerTool, Description("Get active weather alerts for a US state (two-letter code, e.g. 'CA').")]
    public async Task<string> GetAlerts(
        [Description("Two-letter US state code")] string state)
    {
        var response = await _httpClient.GetAsync($"alerts/active/area/{state}");
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(
            await response.Content.ReadAsStreamAsync());
        var features = doc.RootElement.GetProperty("features");

        if (features.GetArrayLength() == 0)
            return $"No active alerts for {state}.";

        var alerts = new List<string>();
        foreach (var feature in features.EnumerateArray().Take(5))
        {
            var props = feature.GetProperty("properties");
            var headline = props.GetProperty("headline").GetString();
            var severity = props.GetProperty("severity").GetString();
            alerts.Add($"[{severity}] {headline}");
        }

        return string.Join("\n", alerts);
    }
}

