using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;

var builder = Host.CreateApplicationBuilder(args);

// Register a named HttpClient for the weather API.
// This is available to tool classes via IHttpClientFactory (injected by DI).
builder.Services.AddHttpClient("WeatherApi", client =>
{
    client.BaseAddress = new Uri("https://api.weather.gov/");
    client.DefaultRequestHeaders.UserAgent.ParseAdd("McpRestServer/1.0");
});

// Register the MCP server with stdio transport.
// WithStdioServerTransport() reads JSON-RPC from stdin, writes to stdout.
// WithToolsFromAssembly() scans for [McpServerToolType] classes and
// registers their [McpServerTool] methods as callable tools.
builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();

await builder.Build().RunAsync();

